(()=>{document.querySelector(".closebtn").addEventListener("click",(function(){document.getElementById("mySidenav").style.width="0",document.getElementById("main").style.marginLeft="0"})),document.querySelector(".open").addEventListener("click",(function(){document.getElementById("mySidenav").style.width="250px",document.getElementById("main").style.marginLeft="250px"}));const e=document.getElementById("container"),t=document.getElementById("overlay"),n=document.querySelector(".add"),c=document.querySelector(".closeform");n.addEventListener("click",(function(){e.classList.add("active"),t.classList.add("active")})),c.addEventListener("click",(function(){e.classList.remove("active"),t.classList.remove("active")}))})();